import sys

def task_hello():
    print('Hello from Python!')

def task_info():
    import platform
    print(f'Python {sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}')
    print(f'Platform: {sys.platform}')

def task_check(value):
    try:
        int(value)
        print(f"'{value}' looks like: int")
        return
    except ValueError:
        pass
    try:
        float(value)
        print(f"'{value}' looks like: float")
        return
    except ValueError:
        pass
    print(f"'{value}' looks like: string")

TASKS = {
    'hello': lambda: task_hello(),
    'info': lambda: task_info(),
    'check': lambda: task_check(sys.argv[2] if len(sys.argv) > 2 else ''),
}

if len(sys.argv) < 2:
    print('Usage: python3 run.py <task>')
    print(f'Available tasks: {", ".join(TASKS)}')
    sys.exit(1)

task_name = sys.argv[1]
if task_name in TASKS:
    TASKS[task_name]()
else:
    print(f'Unknown task: {task_name}')
    print(f'Available tasks: {", ".join(TASKS)}')
